function QRCodeGen() {
  const [text, setText] = React.useState('REPLACE_WITH_TEXT');
  const [size, setSize] = React.useState(200);

  const qrUrl = text ? `https://api.qrserver.com/v1/create-qr-code/?size=${size}x${size}&data=${encodeURIComponent(text)}` : '';

  return (
    <div style={{padding:16,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column',alignItems:'center'}}>
      <div style={{fontSize:18,fontWeight:700,marginBottom:12}}>QR Code Generator</div>
      <input value={text} onChange={e=>setText(e.target.value)}
        style={{width:'100%',padding:'8px 12px',borderRadius:8,border:'1px solid #ccc',fontSize:14,marginBottom:12}}
        placeholder="Enter text or URL…"/>
      <div style={{marginBottom:12}}>
        <span style={{fontSize:12,color:'#888',marginRight:8}}>Size:</span>
        {[150,200,300,400].map(s=> (
          <button key={s} onClick={()=>setSize(s)}
            style={{padding:'4px 10px',marginRight:4,borderRadius:6,border:'1px solid #ccc',background:size===s?'#007AFF':'#fff',color:size===s?'#fff':'#000',cursor:'pointer',fontSize:12}}>
            {s}px
          </button>
        ))}
      </div>
      {qrUrl && (
        <div style={{flex:1,display:'flex',alignItems:'center',justifyContent:'center'}}>
          <img src={qrUrl} style={{maxWidth:'100%',maxHeight:'100%',borderRadius:8}} alt="QR"/>
        </div>
      )}
      {!qrUrl && <div style={{color:'#888',fontSize:14}}>Enter text to generate QR code</div>}
    </div>
  );
}
render(<QRCodeGen/>);
